mapper.select:
 		SELECT COUNT(*) AS CNT
		FROM MA30_BBS_EVENT_ENT
		WHERE USER_HP = #{user_hp}
		AND EVNT_ID = #{evnt_id}
		AND BBS_MK_CD = #{bbs_mk_cd}
		WITH UR

mapper.insert:
INSERT INTO MA30_BBS_EVENT_ENT(
	  BBS_MK_CD	
	, SEQNO	
	, EVNT_ID
	, USER_ID
	, USER_NM
	, USER_BDAY 
	, USER_SEX
	, USER_HP
	, USER_TEL
	, USER_EMAIL
	, USER_POST
	, USER_ADDR1
	, USER_ADDR2
	, ENT_DATE

	, USER_CIFNO

)VALUES(
	  #{bbs_mk_cd}
	, (SELECT MAX(SEQNO) FROM MA30_BBS_EVENT_ENT) + 1
	, #{evnt_id}
	, #{user_id}
	, #{user_nm}
	, #{user_bday}
	, #{user_sex}
	, #{user_hp}
	, #{user_tel}
	, #{user_email}
	, #{user_post}
	, #{user_addr1}
	, #{user_addr2}
	, CURRENT TIMESTAMP

	, #{user_cifno}

)
